-- ng.cu_total_v source

CREATE OR REPLACE VIEW ng.cu_total_v
AS SELECT t.ac_code, t.ocode, t.compno, t.uyear, sum(t.inv_sum) AS inv_sum, 
    sum(t.back_sum) AS back_sum, sum(t.rec_sum) AS rec_sum, 
    sum(t.disc_sum) AS disc_sum, sum(t.bad_sum) AS bad_sum, 
    sum(t.den_sum) AS den_sum, sum(t.crn_sum) AS crn_sum, 
    sum(t.inv_init) AS inv_init, sum(t.rec_init) AS rec_init, 
    sum(t.baln_init) AS baln_init, sum(t.inv_ap00) AS inv_ap00, 
    sum(t.back_ap00) AS back_ap00, sum(t.rec_ap00) AS rec_ap00, 
    sum(t.disc_ap00) AS disc_ap00, sum(t.bad_ap00) AS bad_ap00, 
    sum(t.den_ap00) AS den_ap00, sum(t.crn_ap00) AS crn_ap00, 
    sum(t.inv_ap01) AS inv_ap01, sum(t.back_ap01) AS back_ap01, 
    sum(t.rec_ap01) AS rec_ap01, sum(t.disc_ap01) AS disc_ap01, 
    sum(t.bad_ap01) AS bad_ap01, sum(t.den_ap01) AS den_ap01, 
    sum(t.crn_ap01) AS crn_ap01, sum(t.inv_ap02) AS inv_ap02, 
    sum(t.back_ap02) AS back_ap02, sum(t.rec_ap02) AS rec_ap02, 
    sum(t.disc_ap02) AS disc_ap02, sum(t.bad_ap02) AS bad_ap02, 
    sum(t.den_ap02) AS den_ap02, sum(t.crn_ap02) AS crn_ap02, 
    sum(t.inv_ap03) AS inv_ap03, sum(t.back_ap03) AS back_ap03, 
    sum(t.rec_ap03) AS rec_ap03, sum(t.disc_ap03) AS disc_ap03, 
    sum(t.bad_ap03) AS bad_ap03, sum(t.den_ap03) AS den_ap03, 
    sum(t.crn_ap03) AS crn_ap03, sum(t.inv_ap04) AS inv_ap04, 
    sum(t.back_ap04) AS back_ap04, sum(t.rec_ap04) AS rec_ap04, 
    sum(t.disc_ap04) AS disc_ap04, sum(t.bad_ap04) AS bad_ap04, 
    sum(t.den_ap04) AS den_ap04, sum(t.crn_ap04) AS crn_ap04, 
    sum(t.inv_ap05) AS inv_ap05, sum(t.back_ap05) AS back_ap05, 
    sum(t.rec_ap05) AS rec_ap05, sum(t.disc_ap05) AS disc_ap05, 
    sum(t.bad_ap05) AS bad_ap05, sum(t.den_ap05) AS den_ap05, 
    sum(t.crn_ap05) AS crn_ap05, sum(t.inv_ap06) AS inv_ap06, 
    sum(t.back_ap06) AS back_ap06, sum(t.rec_ap06) AS rec_ap06, 
    sum(t.disc_ap06) AS disc_ap06, sum(t.bad_ap06) AS bad_ap06, 
    sum(t.den_ap06) AS den_ap06, sum(t.crn_ap06) AS crn_ap06, 
    sum(t.inv_ap07) AS inv_ap07, sum(t.back_ap07) AS back_ap07, 
    sum(t.rec_ap07) AS rec_ap07, sum(t.disc_ap07) AS disc_ap07, 
    sum(t.bad_ap07) AS bad_ap07, sum(t.den_ap07) AS den_ap07, 
    sum(t.crn_ap07) AS crn_ap07, sum(t.inv_ap08) AS inv_ap08, 
    sum(t.back_ap08) AS back_ap08, sum(t.rec_ap08) AS rec_ap08, 
    sum(t.disc_ap08) AS disc_ap08, sum(t.bad_ap08) AS bad_ap08, 
    sum(t.den_ap08) AS den_ap08, sum(t.crn_ap08) AS crn_ap08, 
    sum(t.inv_ap09) AS inv_ap09, sum(t.back_ap09) AS back_ap09, 
    sum(t.rec_ap09) AS rec_ap09, sum(t.disc_ap09) AS disc_ap09, 
    sum(t.bad_ap09) AS bad_ap09, sum(t.den_ap09) AS den_ap09, 
    sum(t.crn_ap09) AS crn_ap09, sum(t.inv_ap10) AS inv_ap10, 
    sum(t.back_ap10) AS back_ap10, sum(t.rec_ap10) AS rec_ap10, 
    sum(t.disc_ap10) AS disc_ap10, sum(t.bad_ap10) AS bad_ap10, 
    sum(t.den_ap10) AS den_ap10, sum(t.crn_ap10) AS crn_ap10, 
    sum(t.inv_ap11) AS inv_ap11, sum(t.back_ap11) AS back_ap11, 
    sum(t.rec_ap11) AS rec_ap11, sum(t.disc_ap11) AS disc_ap11, 
    sum(t.bad_ap11) AS bad_ap11, sum(t.den_ap11) AS den_ap11, 
    sum(t.crn_ap11) AS crn_ap11, sum(t.inv_ap12) AS inv_ap12, 
    sum(t.back_ap12) AS back_ap12, sum(t.rec_ap12) AS rec_ap12, 
    sum(t.disc_ap12) AS disc_ap12, sum(t.bad_ap12) AS bad_ap12, 
    sum(t.den_ap12) AS den_ap12, sum(t.crn_ap12) AS crn_ap12, 
    sum(t.inv_ap13) AS inv_ap13, sum(t.back_ap13) AS back_ap13, 
    sum(t.rec_ap13) AS rec_ap13, sum(t.disc_ap13) AS disc_ap13, 
    sum(t.bad_ap13) AS bad_ap13, sum(t.den_ap13) AS den_ap13, 
    sum(t.crn_ap13) AS crn_ap13, sum(t.inv_ap14) AS inv_ap14, 
    sum(t.back_ap14) AS back_ap14, sum(t.rec_ap14) AS rec_ap14, 
    sum(t.disc_ap14) AS disc_ap14, sum(t.bad_ap14) AS bad_ap14, 
    sum(t.den_ap14) AS den_ap14, sum(t.crn_ap14) AS crn_ap14, 
    sum(t.inv_ap15) AS inv_ap15, sum(t.back_ap15) AS back_ap15, 
    sum(t.rec_ap15) AS rec_ap15, sum(t.disc_ap15) AS disc_ap15, 
    sum(t.bad_ap15) AS bad_ap15, sum(t.den_ap15) AS den_ap15, 
    sum(t.crn_ap15) AS crn_ap15
   FROM (        (        (        (        (        (        (        (        (        (        (        (        (        (        (        (        (         SELECT t_in.ac_code, 
                                                                                                                                                    t_in.ocode, 
                                                                                                                                                    t_in.compno, 
                                                                                                                                                    t_in.uyear, 
                                                                                                                                                    0.00 AS inv_sum, 
                                                                                                                                                    0.00 AS back_sum, 
                                                                                                                                                    0.00 AS rec_sum, 
                                                                                                                                                    0.00 AS disc_sum, 
                                                                                                                                                    0.00 AS bad_sum, 
                                                                                                                                                    0.00 AS den_sum, 
                                                                                                                                                    0.00 AS crn_sum, 
                                                                                                                                                        CASE
                                                                                                                                                            WHEN sum(t_in.inv_nc) > 0::bigint::number THEN sum(t_in.inv_nc)
                                                                                                                                                            ELSE 0::bigint::number
                                                                                                                                                        END AS inv_init, 
                                                                                                                                                        CASE
                                                                                                                                                            WHEN sum(t_in.inv_nc) < 0::bigint::number THEN - sum(t_in.inv_nc)
                                                                                                                                                            ELSE 0::bigint::number
                                                                                                                                                        END AS rec_init, 
                                                                                                                                                    sum(t_in.inv_nc) AS baln_init, 
                                                                                                                                                    0.00 AS inv_ap00, 
                                                                                                                                                    0.00 AS back_ap00, 
                                                                                                                                                    0.00 AS rec_ap00, 
