                                                                                                                                                    0.00 AS crn_ap15
                                                                                                                                                   FROM ( SELECT gl_assistant.ac_code, 
                                                                                                                                                            gl_assistant.ocode, 
                                                                                                                                                            gl_assistant.custom AS compno, 
                                                                                                                                                            gl_assistant.uyear, 
                                                                                                                                                            (gl_assistant.bf_bala OPERATOR(dolphin_catalog.+) gl_assistant.de_sum) OPERATOR(dolphin_catalog.-) gl_assistant.cr_sum AS inv_nc
                                                                                                                                                           FROM ng.gl_assistant
                                                                                                                                                          WHERE gl_assistant.custom IS NOT NULL) t_in, 
                                                                                                                                                    ng.gl_post
                                                                                                                                                  WHERE t_in.ocode::text = gl_post.ocode::text AND (gl_post.inited = 0::bigint OR gl_post.inited IS NULL) AND gl_post.uyear::text = t_in.uyear::text
                                                                                                                                                  GROUP BY t_in.ac_code, t_in.ocode, t_in.compno, t_in.uyear
                                                                                                                                        UNION 
                                                                                                                                                 SELECT t_in.ac_code, 
                                                                                                                                                    t_in.ocode, 
                                                                                                                                                    t_in.compno, 
                                                                                                                                                    t_in.uyear, 
                                                                                                                                                    0.00 AS inv_sum, 
                                                                                                                                                    0.00 AS back_sum, 
                                                                                                                                                    0.00 AS rec_sum, 
                                                                                                                                                    0.00 AS disc_sum, 
                                                                                                                                                    0.00 AS bad_sum, 
                                                                                                                                                    0.00 AS den_sum, 
                                                                                                                                                    0.00 AS crn_sum, 
                                                                                                                                                    0.00 AS inv_init, 
                                                                                                                                                    0.00 AS rec_init, 
                                                                                                                                                    0.00 AS baln_init, 
                                                                                                                                                    sum(
                                                                                                                                                        CASE
                                                                                                                                                            WHEN t_in.op_type::text = 'SI'::text OR t_in.op_type::text = 'SL'::text THEN t_in.inv_nc
                                                                                                                                                            ELSE 0::number
                                                                                                                                                        END) AS inv_ap00, 
                                                                                                                                                    sum(
                                                                                                                                                        CASE
                                                                                                                                                            WHEN t_in.op_type::text = 'SC'::text THEN t_in.inv_nc
                                                                                                                                                            ELSE 0::number
                                                                                                                                                        END) AS back_ap00, 
                                                                                                                                                    sum(
                                                                                                                                                        CASE
                                                                                                                                                            WHEN t_in.op_type::text = 'SR'::text OR t_in.op_type::text = 'SX'::text OR t_in.op_type::text = 'SV'::text OR t_in.op_type::text = 'ST'::text THEN t_in.rec_nc
                                                                                                                                                            WHEN t_in.op_type::text = 'SA'::text THEN t_in.inv_nc
                                                                                                                                                            ELSE 0::number
                                                                                                                                                        END) AS rec_ap00, 
                                                                                                                                                    sum(
                                                                                                                                                        CASE
                                                                                                                                                            WHEN t_in.op_type::text = 'SD'::text THEN t_in.disc_nc
                                                                                                                                                            ELSE 0::number
                                                                                                                                                        END) AS disc_ap00, 
                                                                                                                                                    sum(
                                                                                                                                                        CASE
                                                                                                                                                            WHEN t_in.op_type::text = 'SB'::text THEN t_in.inv_nc
                                                                                                                                                            WHEN t_in.op_type::text = 'SM'::text THEN - t_in.inv_nc
                                                                                                                                                            ELSE 0::number
                                                                                                                                                        END) AS bad_ap00, 
                                                                                                                                                    sum(t_in.de_tran) AS den_ap00, 
                                                                                                                                                    sum(t_in.cr_tran) AS crn_ap00, 
