                                                                                                                                                            ( SELECT accper.uyear
                                                                                                                                                                   FROM ng.accper
                                                                                                                                                                  WHERE cu_bill.tr_date >= accper.begindt AND cu_bill.tr_date <= accper.enddt) AS uyear, 
