                                                                                                                                                    ng.gl_post
                                                                                                                                                  WHERE t_in.ocode::text = gl_post.ocode::text AND (gl_post.inited = 0 OR gl_post.inited IS NULL) AND gl_post.uyear::text = t_in.uyear::text
